1	export type Cell = [number, number];
2	
3	function cellsEqual(cell: Cell, other: Cell): boolean {
4	  return other[0] === cell[0] && other[1] === cell[1];
5	}
6	
7	function isNeighbor(cell: Cell, other: Cell): boolean {
8	  return (
9	    !cellsEqual(cell, other) &&
10	    Math.abs(other[0] - cell[0]) <= 1 &&
11	    Math.abs(other[1] - cell[1]) <= 1
12	  );
13	}
14	
15	function countNeighbors(cell: Cell, cells: Cell[]): number {
16	  return cells.filter((other) => isNeighbor(cell, other)).length;
17	}
18	
19	function isLive(cell: Cell, cells: Cell[]): boolean {
20	  return cells.some((other) => cellsEqual(cell, other));
21	}
22	
23	function deadNeighborCandidates(cells: Cell[]): Cell[] {
24	  const offsets = [-1, 0, 1];
25	  const candidates: Cell[] = [];
26	  for (const cell of cells) {
27	    for (const dx of offsets) {
28	      for (const dy of offsets) {
29	        const candidate: Cell = [cell[0] + dx, cell[1] + dy];
30	        if (isLive(candidate, cells)) continue;
31	        if (isLive(candidate, candidates)) continue;
32	        candidates.push(candidate);
33	      }
34	    }
35	  }
36	  return candidates;
37	}
38	
39	export function nextGeneration(cells: Cell[]): Cell[] {
40	  const survivors = cells.filter((cell) => {
41	    const neighborCount = countNeighbors(cell, cells);
42	    return neighborCount === 2 || neighborCount === 3;
43	  });
44	
45	  const births = deadNeighborCandidates(cells).filter(
46	    (candidate) => countNeighbors(candidate, cells) === 3,
47	  );
48	
49	  return [...survivors, ...births];
50	}
